lemma RepDistinct(i: nat, j: nat)
  requires i != j
  ensures Rep(i) != Rep(j)
{
  if i < j {
    RepLength(i);
    RepLength(j);
    assert |Rep(i)| == i;
    assert |Rep(j)| == j;
    assert i < j ==> |Rep(i)| < |Rep(j)|;
    // hence cannot be equal
  } else {
    // j < i
    RepDistinct(j, i);
  }
}

lemma FreshCodeExists<T>(m: map<string, T>)
  ensures exists j :: 0 <= j <= |m| && Rep(j) !in m
{
  var M := |m| + 1;
  // If it were the case that every Rep(j) for j in 0..|m| were in m,
  // then there would be M distinct elements of m (because Rep(i) have different lengths),
  // contradicting that m has only |m| elements.
  if forall j :: 0 <= j <= |m| ==> Rep(j) in m {
    // show the Rep values are pairwise distinct and all in m,
    // therefore m would have at least M distinct keys -> contradiction
    // Build a proof that |m| >= M, contradicting M = |m| + 1.
    // For i != j in [0..|m|], Rep(i) != Rep(j) by RepDistinct.
    // Hence there are M distinct elements in m, so |m| >= M.
    // This yields a contradiction with M = |m| + 1.
    // Formalize:
    // From the forall above we have: forall k :: 0 <= k < M ==> Rep(k) in m
    assert forall k :: 0 <= k < M ==> Rep(k) in m by {
      var kk := 0;
      while kk < M
        invariant 0 <= kk <= M
      {
        assert 0 <= kk <= |m|;
        assert Rep(kk) in m; // from the forall hypothesis
        kk := kk + 1;
      }
    }
    // Show pairwise distinctness
    assert forall i, j :: 0 <= i < M && 0 <= j < M && i != j ==> Rep(i) != Rep(j) by {
      var ii := 0;
      while ii < M
        invariant 0 <= ii <= M
      {
        var jj := 0;
        while jj < M
          invariant 0 <= jj <= M
