}

method Shorten(st: ServiceState, url: LongURL) returns (code: ShortCode, short_url: string)
  requires ServiceStateInv(st)
  requires LongURLWhere(url)
  requires isValidURI(url)
  ensures code !in old(st.store)
  ensures st.store == old(st.store)[code := url]
  ensures short_url == old(st.base_url) + "/" + code
  ensures |st.store| == |old(st.store)| + 1
  ensures (code in st.metadata && st.metadata[code].url == url)
  ensures (code in st.metadata && st.metadata[code].click_count == 0)
  ensures ServiceStateInv(st)
  modifies st
{
  // Capture old state in locals to refer to them constructively
  var oldStore := st.store;
  var oldMetadata := st.metadata;
  var oldBase := st.base_url;

  // Sanity facts from the precondition ServiceStateInv(st)
  assert (forall c :: c in oldStore ==> isValidURI(oldStore[c]));
  assert oldStore.Keys == oldMetadata.Keys;
  assert (forall c :: c in oldMetadata ==> oldMetadata[c].click_count >= 0);

  // Use pigeonhole lemma to obtain an index target with Rep(target) not in oldStore
  FreshCodeExists(oldStore);
  assert exists t :: 0 <= t <= |oldStore| && Rep(t) !in oldStore;
  var target : int :| 0 <= target <= |oldStore| && Rep(target) !in oldStore;

  // Search from shorter to longer reps until we hit the chosen target (which is known fresh).
  var i := 0;
  code := Rep(0);
  while code in oldStore && i < target
    decreases target - i
    invariant 0 <= i <= target
    invariant code == Rep(i)
  {
    i := i + 1;
    code := Rep(i);
  }

  // Now code must be fresh: either we exited because code !in oldStore, or because i == target,
  // but Rep(target) is guaranteed not in oldStore.
  assert code !in oldStore;

  // Update the store and metadata consistently
  st.store := oldStore[code := url];
  st.metadata := oldMetadata[code := UrlMapping(code, url, 0, 0)];
  // short URL as required
  short_url := oldBase + "/" + code;

  // Verify the straightforward equalities used in postconditions
  assert st.store == oldStore[code := url];
  assert st.metadata[code].url == url;
  assert st.metadata[code].click_count == 0;
  assert short_url == oldBase + "/" + code;
  assert |st.store| == |oldStore| + 1;

  // Prove ServiceStateInv(st):
  // 1) All values in st.store are valid URIs:
  //    - For the newly inserted code: isValidURI(url) holds by precondition.
  //    - For other keys: values come from oldStore, which satisfied ServiceStateInv(st).
  assert (forall c :: c in st.store ==> isValidURI(st.store[c]));
  // 2) Keys equality between store and metadata:
  assert st.store.Keys == st.metadata.Keys;
  // 3) All metadata click_counts are non-negative:
  assert (forall c :: c in st.metadata ==> st.metadata[c].click_count >= 0);

  // Final ServiceStateInv
  assert ServiceStateInv(st);
}

